        if (log_parser_stats)
                ShowUsage("PARSE ANALYSIS STATISTICS");

        /*
         * (2) Rewrite the queries, as necessary
         */
        querytree_list = pg_rewrite_query(query);

        TRACE_POSTGRESQL_QUERY_REWRITE_DONE(query_string);

        return querytree_list;
}

