ExecInitNode(Plan *node, EState *estate, int eflags)
{
        PlanState  *result;
        List       *subps;
        ListCell   *l;

        /*
         * do nothing when we get to the end of a leaf on tree.
         */
        if (node == NULL)
                return NULL;

        /*
         * Make sure there's enough stack available. Need to check here, in
         * addition to ExecProcNode() (via ExecProcNodeFirst()), to ensure the
         * stack isn't overrun while initializing the node tree.
         */
        check_stack_depth();

        switch (nodeTag(node))
        {
                        /*
                         * control nodes
                         */
                case T_Result:
                        result = (PlanState *) ExecInitResult((Result *) node,
                                                                                                  estate, eflags);
                        break;

                case T_ProjectSet:
                        result = (PlanState *) ExecInitProjectSet((ProjectSet *) node,
                                                                                                          estate, eflags);
                        break;

                case T_ModifyTable:
                        result = (PlanState *) ExecInitModifyTable((ModifyTable *) node,
                                                                                                           estate, eflags);
                        break;

                case T_Append:
                        result = (PlanState *) ExecInitAppend((Append *) node,
                                                                                                  estate, eflags);
                        break;

                case T_MergeAppend:
                        result = (PlanState *) ExecInitMergeAppend((MergeAppend *) node,
                                                                                                           estate, eflags);
                        break;

                case T_RecursiveUnion:
                        result = (PlanState *) ExecInitRecursiveUnion((RecursiveUnion *) node,
                                                                                                                  estate, eflags);
                        break;

                case T_BitmapAnd:
                        result = (PlanState *) ExecInitBitmapAnd((BitmapAnd *) node,
                                                                                                         estate, eflags);
                        break;

                case T_BitmapOr:
                        result = (PlanState *) ExecInitBitmapOr((BitmapOr *) node,
                                                                                                        estate, eflags);
                        break;

                        /*
                         * scan nodes
                         */
                case T_SeqScan:
                        result = (PlanState *) ExecInitSeqScan((SeqScan *) node,
                                                                                                   estate, eflags);
                        break;

                case T_SampleScan:
                        result = (PlanState *) ExecInitSampleScan((SampleScan *) node,
                                                                                                          estate, eflags);
                        break;

                case T_IndexScan:
                        result = (PlanState *) ExecInitIndexScan((IndexScan *) node,
                                                                                                         estate, eflags);
                        break;

                case T_IndexOnlyScan:
                        result = (PlanState *) ExecInitIndexOnlyScan((IndexOnlyScan *) node,
                                                                                                                 estate, eflags);
                        break;

                case T_BitmapIndexScan:
                        result = (PlanState *) ExecInitBitmapIndexScan((BitmapIndexScan *) node,
                                                                                                                   estate, eflags);
                        break;

                case T_BitmapHeapScan:
                        result = (PlanState *) ExecInitBitmapHeapScan((BitmapHeapScan *) node,
                                                                                                                  estate, eflags);
                        break;

                case T_TidScan:
                        result = (PlanState *) ExecInitTidScan((TidScan *) node,
                                                                                                   estate, eflags);
                        break;

                case T_TidRangeScan:
                        result = (PlanState *) ExecInitTidRangeScan((TidRangeScan *) node,
                                                                                                                estate, eflags);
                        break;

                case T_SubqueryScan:
                        result = (PlanState *) ExecInitSubqueryScan((SubqueryScan *) node,
                                                                                                                estate, eflags);
                        break;

                case T_FunctionScan:
                        result = (PlanState *) ExecInitFunctionScan((FunctionScan *) node,
                                                                                                                estate, eflags);
                        break;

                case T_TableFuncScan:
                        result = (PlanState *) ExecInitTableFuncScan((TableFuncScan *) node,
                                                                                                                 estate, eflags);
                        break;

                case T_ValuesScan:
                        result = (PlanState *) ExecInitValuesScan((ValuesScan *) node,
                                                                                                          estate, eflags);
                        break;

                case T_CteScan:
                        result = (PlanState *) ExecInitCteScan((CteScan *) node,
                                                                                                   estate, eflags);
                        break;

                case T_NamedTuplestoreScan:
                        result = (PlanState *) ExecInitNamedTuplestoreScan((NamedTuplestoreScan *) node,
                                                                                                                           estate, eflags);
                        break;

                case T_WorkTableScan:
                        result = (PlanState *) ExecInitWorkTableScan((WorkTableScan *) node,
                                                                                                                 estate, eflags);
                        break;

                case T_ForeignScan:
                        result = (PlanState *) ExecInitForeignScan((ForeignScan *) node,
                                                                                                           estate, eflags);
                        break;

                case T_CustomScan:
                        result = (PlanState *) ExecInitCustomScan((CustomScan *) node,
                                                                                                          estate, eflags);
                        break;

                        /*
                         * join nodes
                         */
                case T_NestLoop:
                        result = (PlanState *) ExecInitNestLoop((NestLoop *) node,
                                                                                                        estate, eflags);
                        break;

break;

                case T_MergeJoin:
                        result = (PlanState *) ExecInitMergeJoin((MergeJoin *) node,
                                                                                                         estate, eflags);
                        break;

                case T_HashJoin:
                        result = (PlanState *) ExecInitHashJoin((HashJoin *) node,
                                                                                                        estate, eflags);
                        break;

                        /*
                         * materialization nodes
                         */
                case T_Material:
                        result = (PlanState *) ExecInitMaterial((Material *) node,
                                                                                                        estate, eflags);
                        break;

                case T_Sort:
                        result = (PlanState *) ExecInitSort((Sort *) node,
                                                                                                estate, eflags);
                        break;

                case T_IncrementalSort:
                        result = (PlanState *) ExecInitIncrementalSort((IncrementalSort *) node,
                                                                                                                   estate, eflags);
                        break;

                case T_Memoize:
                        result = (PlanState *) ExecInitMemoize((Memoize *) node, estate,
                                                                                                   eflags);
                        break;

                case T_Group:
                        result = (PlanState *) ExecInitGroup((Group *) node,
                                                                                                 estate, eflags);
                        break;

                case T_Agg:
                        result = (PlanState *) ExecInitAgg((Agg *) node,
                                                                                           estate, eflags);
                        break;

                case T_WindowAgg:
                        result = (PlanState *) ExecInitWindowAgg((WindowAgg *) node,
                                                                                                         estate, eflags);
                        break;

                case T_Unique:
                        result = (PlanState *) ExecInitUnique((Unique *) node,
                                                                                                  estate, eflags);
                        break;

                case T_Gather:
                        result = (PlanState *) ExecInitGather((Gather *) node,
                                                                                                  estate, eflags);
                        break;

                case T_GatherMerge:
                        result = (PlanState *) ExecInitGatherMerge((GatherMerge *) node,
                                                                                                           estate, eflags);
                        break;

                case T_Hash:
                        result = (PlanState *) ExecInitHash((Hash *) node,
                                                                                                estate, eflags);
                        break;

                case T_SetOp:
                        result = (PlanState *) ExecInitSetOp((SetOp *) node,
                                                                                                 estate, eflags);
                        break;

                case T_LockRows:
                        result = (PlanState *) ExecInitLockRows((LockRows *) node,
                                                                                                        estate, eflags);
                        break;

                case T_Limit:
                        result = (PlanState *) ExecInitLimit((Limit *) node,
                                                                                                 estate, eflags);
                        break;

                default:
                        elog(ERROR, "unrecognized node type: %d", (int) nodeTag(node));
                        result = NULL;          /* keep compiler quiet */
                        break;
        }

        ExecSetExecProcNode(result, result->ExecProcNode);

        /*
         * Initialize any initPlans present in this node.  The planner put them in
         * a separate list for us.
         *
         * The defining characteristic of initplans is that they don't have
         * arguments, so we don't need to evaluate them (in contrast to
         * ExecInitSubPlanExpr()).
         */
        subps = NIL;
        foreach(l, node->initPlan)
        {
                SubPlan    *subplan = (SubPlan *) lfirst(l);
                SubPlanState *sstate;

                Assert(IsA(subplan, SubPlan));
                Assert(subplan->args == NIL);
                sstate = ExecInitSubPlan(subplan, result);
                subps = lappend(subps, sstate);
        }
        result->initPlan = subps;

        /* Set up instrumentation for this node if requested */
        if (estate->es_instrument)
                result->instrument = InstrAlloc(1, estate->es_instrument,
                                                                                result->async_capable);

        return result;
}


/*
 * If a node wants to change its ExecProcNode function after ExecInitNode()
 * has finished, it should do so with this function.  That way any wrapper
 * functions can be reinstalled, without the node having to know how that
 * works.
 */
void
ExecSetExecProcNode(PlanState *node, ExecProcNodeMtd function)
{
        /*
         * Add a wrapper around the ExecProcNode callback that checks stack depth
         * during the first execution and maybe adds an instrumentation wrapper.
         * When the callback is changed after execution has already begun that
         * means we'll superfluously execute ExecProcNodeFirst, but that seems ok.
         */
        node->ExecProcNodeReal = function;
        node->ExecProcNode = ExecProcNodeFirst;
}


/*
 * ExecProcNode wrapper that performs some one-time checks, before calling
 * the relevant node method (possibly via an instrumentation wrapper).
 */
static TupleTableSlot *
ExecProcNodeFirst(PlanState *node)
{
        /*

ExecProcNodeFirst(PlanState *node)
{
        /*
         * Perform stack depth check during the first execution of the node.  We
         * only do so the first time round because it turns out to not be cheap on
         * some common architectures (eg. x86).  This relies on the assumption
         * that ExecProcNode calls for a given plan node will always be made at
         * roughly the same stack depth.
         */
        check_stack_depth();

        /*
         * If instrumentation is required, change the wrapper to one that just
         * does instrumentation.  Otherwise we can dispense with all wrappers and
         * have ExecProcNode() directly call the relevant function from now on.
         */
        if (node->instrument)
                node->ExecProcNode = ExecProcNodeInstr;
        else
                node->ExecProcNode = node->ExecProcNodeReal;

        return node->ExecProcNode(node);
}


/*
 * ExecProcNode wrapper that performs instrumentation calls.  By keeping
 * this a separate function, we avoid overhead in the normal case where
 * no instrumentation is wanted.
 */
static TupleTableSlot *
ExecProcNodeInstr(PlanState *node)
{
        TupleTableSlot *result;

        InstrStartNode(node->instrument);

        result = node->ExecProcNodeReal(node);

        InstrStopNode(node->instrument, TupIsNull(result) ? 0.0 : 1.0);

        return result;
}


