ExecutePlan(QueryDesc *queryDesc,
                        CmdType operation,
                        bool sendTuples,
                        uint64 numberTuples,
                        ScanDirection direction,
                        DestReceiver *dest)
{
        EState     *estate = queryDesc->estate;
        PlanState  *planstate = queryDesc->planstate;
        bool            use_parallel_mode;
        TupleTableSlot *slot;
        uint64          current_tuple_count;

        /*
         * initialize local variables
         */
        current_tuple_count = 0;

        /*
         * Set the direction.
         */
        estate->es_direction = direction;

        /*
         * Set up parallel mode if appropriate.
         *
         * Parallel mode only supports complete execution of a plan.  If we've
         * already partially executed it, or if the caller asks us to exit early,
         * we must force the plan to run without parallelism.
         */
        if (queryDesc->already_executed || numberTuples != 0)
                use_parallel_mode = false;
        else
                use_parallel_mode = queryDesc->plannedstmt->parallelModeNeeded;
        queryDesc->already_executed = true;

        estate->es_use_parallel_mode = use_parallel_mode;
        if (use_parallel_mode)
                EnterParallelMode();

        /*
         * Loop until we've processed the proper number of tuples from the plan.
         */
        for (;;)
        {
                /* Reset the per-output-tuple exprcontext */
                ResetPerTupleExprContext(estate);

                /*
                 * Execute the plan and obtain a tuple
                 */
                slot = ExecProcNode(planstate);

                /*
                 * if the tuple is null, then we assume there is nothing more to
                 * process so we just end the loop...
                 */
                if (TupIsNull(slot))
                        break;

                /*
                 * If we have a junk filter, then project a new tuple with the junk
                 * removed.
                 *
                 * Store this new "clean" tuple in the junkfilter's resultSlot.
                 * (Formerly, we stored it back over the "dirty" tuple, which is WRONG
                 * because that tuple slot has the wrong descriptor.)
                 */
                if (estate->es_junkFilter != NULL)
                        slot = ExecFilterJunk(estate->es_junkFilter, slot);

                /*
                 * If we are supposed to send the tuple somewhere, do so. (In
                 * practice, this is probably always the case at this point.)
                 */
                if (sendTuples)
                {
                        /*
                         * If we are not able to send the tuple, we assume the destination
                         * has closed and no more tuples can be sent. If that's the case,
                         * end the loop.
                         */
                        if (!dest->receiveSlot(slot, dest))
                                break;
                }

                /*
                 * Count tuples processed, if this is a SELECT.  (For other operation
                 * types, the ModifyTable plan node must count the appropriate
                 * events.)
                 */
                if (operation == CMD_SELECT)
                        (estate->es_processed)++;

                /*
                 * check our tuple count.. if we've processed the proper number then
                 * quit, else loop again and process more tuples.  Zero numberTuples
                 * means no limit.
                 */
                current_tuple_count++;
                if (numberTuples && numberTuples == current_tuple_count)
                        break;
        }

        /*
         * If we know we won't need to back up, we can release resources at this
         * point.
         */
        if (!(estate->es_top_eflags & EXEC_FLAG_BACKWARD))
                ExecShutdownNode(planstate);

        if (use_parallel_mode)
                ExitParallelMode();
}


/*
 * ExecRelCheck --- check that tuple meets check constraints for result relation
 *
 * Returns NULL if OK, else name of failed check constraint
 */

ExecutorStart(QueryDesc *queryDesc, int eflags)
{
        /*
         * In some cases (e.g. an EXECUTE statement or an execute message with the
         * extended query protocol) the query_id won't be reported, so do it now.
         *
         * Note that it's harmless to report the query_id multiple times, as the
         * call will be ignored if the top level query_id has already been
         * reported.
         */
        pgstat_report_query_id(queryDesc->plannedstmt->queryId, false);

        if (ExecutorStart_hook)
                (*ExecutorStart_hook) (queryDesc, eflags);
        else
                standard_ExecutorStart(queryDesc, eflags);
}

void
standard_ExecutorStart(QueryDesc *queryDesc, int eflags)
{
        EState     *estate;
        MemoryContext oldcontext;

        /* sanity checks: queryDesc must not be started already */
        Assert(queryDesc != NULL);
        Assert(queryDesc->estate == NULL);

        /* caller must ensure the query's snapshot is active */
        Assert(GetActiveSnapshot() == queryDesc->snapshot);

        /*
         * If the transaction is read-only, we need to check if any writes are
         * planned to non-temporary tables.  EXPLAIN is considered read-only.
         *
         * Don't allow writes in parallel mode.  Supporting UPDATE and DELETE
         * would require (a) storing the combo CID hash in shared memory, rather
         * than synchronizing it just once at the start of parallelism, and (b) an
         * alternative to heap_update()'s reliance on xmax for mutual exclusion.
         * INSERT may have no such troubles, but we forbid it to simplify the
         * checks.
         *
         * We have lower-level defenses in CommandCounterIncrement and elsewhere
         * against performing unsafe operations in parallel mode, but this gives a
         * more user-friendly error message.
         */
        if ((XactReadOnly || IsInParallelMode()) &&
                !(eflags & EXEC_FLAG_EXPLAIN_ONLY))
                ExecCheckXactReadOnly(queryDesc->plannedstmt);

        /*
         * Build EState, switch into per-query memory context for startup.
         */
        estate = CreateExecutorState();
        queryDesc->estate = estate;

        oldcontext = MemoryContextSwitchTo(estate->es_query_cxt);

        /*
         * Fill in external parameters, if any, from queryDesc; and allocate
         * workspace for internal parameters
         */
        estate->es_param_list_info = queryDesc->params;

        if (queryDesc->plannedstmt->paramExecTypes != NIL)
        {
                int                     nParamExec;

                nParamExec = list_length(queryDesc->plannedstmt->paramExecTypes);
                estate->es_param_exec_vals = (ParamExecData *)
                        palloc0(nParamExec * sizeof(ParamExecData));
        }

        /* We now require all callers to provide sourceText */
        Assert(queryDesc->sourceText != NULL);
        estate->es_sourceText = queryDesc->sourceText;

        /*
         * Fill in the query environment, if any, from queryDesc.
         */
        estate->es_queryEnv = queryDesc->queryEnv;

        /*
         * If non-read-only query, set the command ID to mark output tuples with
         */
        switch (queryDesc->operation)
        {
                case CMD_SELECT:

                        /*
                         * SELECT FOR [KEY] UPDATE/SHARE and modifying CTEs need to mark
                         * tuples
                         */
                        if (queryDesc->plannedstmt->rowMarks != NIL ||
                                queryDesc->plannedstmt->hasModifyingCTE)
                                estate->es_output_cid = GetCurrentCommandId(true);

                        /*
                         * A SELECT without modifying CTEs can't possibly queue triggers,
                         * so force skip-triggers mode. This is just a marginal efficiency
                         * hack, since AfterTriggerBeginQuery/AfterTriggerEndQuery aren't
                         * all that expensive, but we might as well do it.
                         */
                        if (!queryDesc->plannedstmt->hasModifyingCTE)
                                eflags |= EXEC_FLAG_SKIP_TRIGGERS;
                        break;

                case CMD_INSERT:
                case CMD_DELETE:
                case CMD_UPDATE:
                case CMD_MERGE:
                        estate->es_output_cid = GetCurrentCommandId(true);
                        break;

                default:
                        elog(ERROR, "unrecognized operation code: %d",
                                 (int) queryDesc->operation);
                        break;
        }

        /*
         * Copy other important information into the EState
         */
        estate->es_snapshot = RegisterSnapshot(queryDesc->snapshot);
        estate->es_crosscheck_snapshot = RegisterSnapshot(queryDesc->crosscheck_snapshot);
        estate->es_top_eflags = eflags;
        estate->es_instrument = queryDesc->instrument_options;
        estate->es_jit_flags = queryDesc->plannedstmt->jitFlags;

        /*
         * Set up an AFTER-trigger statement context, unless told not to, or
         * unless it's EXPLAIN-only mode (when ExecutorFinish won't be called).
         */
        if (!(eflags & (EXEC_FLAG_SKIP_TRIGGERS | EXEC_FLAG_EXPLAIN_ONLY)))
                AfterTriggerBeginQuery();

        /*
         * Initialize the plan state tree
         */
        InitPlan(queryDesc, eflags);

        MemoryContextSwitchTo(oldcontext);
}

/* ----------------------------------------------------------------
 *              ExecutorRun
 *
 *              This is the main routine of the executor module. It accepts
 *              the query descriptor from the traffic cop and executes the
 *              query plan.
 *
 *              ExecutorStart must have been called already.
 *
 *              If direction is NoMovementScanDirection then nothing is done
 *              except to start up/shut down the destination.  Otherwise,
 *              we retrieve up to 'count' tuples in the specified direction.
 *
 *              Note: count = 0 is interpreted as no portal limit, i.e., run to
 *              completion.  Also note that the count limit is only applied to
 *              retrieved tuples, not for instance to those inserted/updated/deleted
 *              by a ModifyTable plan node.
 *
 *              There is no return value, but output tuples (if any) are sent to
 *              the destination receiver specified in the QueryDesc; and the number
 *              of tuples processed at the top level can be found in
 *              estate->es_processed.  The total number of tuples processed in all
 *              the ExecutorRun calls can be found in estate->es_total_processed.
 *
 *              We provide a function hook variable that lets loadable plugins
 *              get control when ExecutorRun is called.  Such a plugin would
 *              normally call standard_ExecutorRun().
 *
 * ----------------------------------------------------------------
 */
void
ExecutorRun(QueryDesc *queryDesc,
                        ScanDirection direction, uint64 count)
{
        if (ExecutorRun_hook)

standard_ExecutorRun(QueryDesc *queryDesc,
                                         ScanDirection direction, uint64 count)
{
        EState     *estate;
        CmdType         operation;
        DestReceiver *dest;
        bool            sendTuples;
        MemoryContext oldcontext;

        /* sanity checks */
        Assert(queryDesc != NULL);

        estate = queryDesc->estate;

        Assert(estate != NULL);
        Assert(!(estate->es_top_eflags & EXEC_FLAG_EXPLAIN_ONLY));

        /* caller must ensure the query's snapshot is active */
        Assert(GetActiveSnapshot() == estate->es_snapshot);

        /*
         * Switch into per-query memory context
         */
        oldcontext = MemoryContextSwitchTo(estate->es_query_cxt);

        /* Allow instrumentation of Executor overall runtime */
        if (queryDesc->totaltime)
                InstrStartNode(queryDesc->totaltime);

        /*
         * extract information from the query descriptor and the query feature.
         */
        operation = queryDesc->operation;
        dest = queryDesc->dest;

        /*
         * startup tuple receiver, if we will be emitting tuples
         */
        estate->es_processed = 0;

        sendTuples = (operation == CMD_SELECT ||
                                  queryDesc->plannedstmt->hasReturning);

        if (sendTuples)
                dest->rStartup(dest, operation, queryDesc->tupDesc);

        /*
         * Run plan, unless direction is NoMovement.
         *
         * Note: pquery.c selects NoMovement if a prior call already reached
         * end-of-data in the user-specified fetch direction.  This is important
         * because various parts of the executor can misbehave if called again
         * after reporting EOF.  For example, heapam.c would actually restart a
         * heapscan and return all its data afresh.  There is also some doubt
         * about whether a parallel plan would operate properly if an additional,
         * necessarily non-parallel execution request occurs after completing a
         * parallel execution.  (That case should work, but it's untested.)
         */
        if (!ScanDirectionIsNoMovement(direction))
                ExecutePlan(queryDesc,
                                        operation,
                                        sendTuples,
                                        count,
                                        direction,
                                        dest);

        /*
         * Update es_total_processed to keep track of the number of tuples
         * processed across multiple ExecutorRun() calls.
         */
        estate->es_total_processed += estate->es_processed;

        /*
         * shutdown tuple receiver, if we started it
         */
        if (sendTuples)
                dest->rShutdown(dest);

        if (queryDesc->totaltime)
                InstrStopNode(queryDesc->totaltime, estate->es_processed);

        MemoryContextSwitchTo(oldcontext);
}

/* ----------------------------------------------------------------
 *              ExecutorFinish
 *
 *              This routine must be called after the last ExecutorRun call.
 *              It performs cleanup such as firing AFTER triggers.  It is
 *              separate from ExecutorEnd because EXPLAIN ANALYZE needs to
 *              include these actions in the total runtime.
 *
 *              We provide a function hook variable that lets loadable plugins
 *              get control when ExecutorFinish is called.  Such a plugin would
 *              normally call standard_ExecutorFinish().
 *
 * ----------------------------------------------------------------
 */
void
ExecutorFinish(QueryDesc *queryDesc)
{
        if (ExecutorFinish_hook)
                (*ExecutorFinish_hook) (queryDesc);
        else
                standard_ExecutorFinish(queryDesc);
}

void
standard_ExecutorFinish(QueryDesc *queryDesc)
{
        EState     *estate;
        MemoryContext oldcontext;

        /* sanity checks */

PortalStart(Portal portal, ParamListInfo params,
                        int eflags, Snapshot snapshot)
{
        Portal          saveActivePortal;
        ResourceOwner saveResourceOwner;
        MemoryContext savePortalContext;
        MemoryContext oldContext;
        QueryDesc  *queryDesc;
        int                     myeflags;

        Assert(PortalIsValid(portal));
        Assert(portal->status == PORTAL_DEFINED);

        /*
         * Set up global portal context pointers.
         */
        saveActivePortal = ActivePortal;
        saveResourceOwner = CurrentResourceOwner;
        savePortalContext = PortalContext;
        PG_TRY();
        {
                ActivePortal = portal;
                if (portal->resowner)
                        CurrentResourceOwner = portal->resowner;
                PortalContext = portal->portalContext;

                oldContext = MemoryContextSwitchTo(PortalContext);

                /* Must remember portal param list, if any */
                portal->portalParams = params;

                /*
                 * Determine the portal execution strategy
                 */
                portal->strategy = ChoosePortalStrategy(portal->stmts);

                /*
                 * Fire her up according to the strategy
                 */
                switch (portal->strategy)
                {
                        case PORTAL_ONE_SELECT:

                                /* Must set snapshot before starting executor. */
                                if (snapshot)
                                        PushActiveSnapshot(snapshot);
                                else
                                        PushActiveSnapshot(GetTransactionSnapshot());

                                /*
                                 * We could remember the snapshot in portal->portalSnapshot,
                                 * but presently there seems no need to, as this code path
                                 * cannot be used for non-atomic execution.  Hence there can't
                                 * be any commit/abort that might destroy the snapshot.  Since
                                 * we don't do that, there's also no need to force a
                                 * non-default nesting level for the snapshot.
                                 */

                                /*
                                 * Create QueryDesc in portal's context; for the moment, set
                                 * the destination to DestNone.
                                 */
                                queryDesc = CreateQueryDesc(linitial_node(PlannedStmt, portal->stmts),
                                                                                        portal->sourceText,
                                                                                        GetActiveSnapshot(),
                                                                                        InvalidSnapshot,
                                                                                        None_Receiver,
                                                                                        params,
                                                                                        portal->queryEnv,
                                                                                        0);

                                /*
                                 * If it's a scrollable cursor, executor needs to support
                                 * REWIND and backwards scan, as well as whatever the caller
                                 * might've asked for.
                                 */
                                if (portal->cursorOptions & CURSOR_OPT_SCROLL)
                                        myeflags = eflags | EXEC_FLAG_REWIND | EXEC_FLAG_BACKWARD;
                                else
                                        myeflags = eflags;

                                /*
                                 * Call ExecutorStart to prepare the plan for execution
                                 */
                                ExecutorStart(queryDesc, myeflags);

                                /*
                                 * This tells PortalCleanup to shut down the executor
                                 */
                                portal->queryDesc = queryDesc;

                                /*
                                 * Remember tuple descriptor (computed by ExecutorStart)
                                 */
                                portal->tupDesc = queryDesc->tupDesc;

                                /*
                                 * Reset cursor position data to "start of query"
                                 */
                                portal->atStart = true;
                                portal->atEnd = false;  /* allow fetches */
                                portal->portalPos = 0;

                                PopActiveSnapshot();
                                break;

                        case PORTAL_ONE_RETURNING:
                        case PORTAL_ONE_MOD_WITH:

                                /*
                                 * We don't start the executor until we are told to run the
                                 * portal.  We do need to set up the result tupdesc.
                                 */
                                {
                                        PlannedStmt *pstmt;

                                        pstmt = PortalGetPrimaryStmt(portal);
                                        portal->tupDesc =
                                                ExecCleanTypeFromTL(pstmt->planTree->targetlist);
                                }

                                /*
                                 * Reset cursor position data to "start of query"
                                 */
                                portal->atStart = true;
                                portal->atEnd = false;  /* allow fetches */
                                portal->portalPos = 0;
                                break;

                        case PORTAL_UTIL_SELECT:

                                /*
                                 * We don't set snapshot here, because PortalRunUtility will
                                 * take care of it if needed.
                                 */
                                {
                                        PlannedStmt *pstmt = PortalGetPrimaryStmt(portal);

                                        Assert(pstmt->commandType == CMD_UTILITY);
                                        portal->tupDesc = UtilityTupleDescriptor(pstmt->utilityStmt);
                                }

                                /*
                                 * Reset cursor position data to "start of query"
                                 */
                                portal->atStart = true;
                                portal->atEnd = false;  /* allow fetches */
                                portal->portalPos = 0;
                                break;

                        case PORTAL_MULTI_QUERY:
                                /* Need do nothing now */
                                portal->tupDesc = NULL;
                                break;
                }
        }
        PG_CATCH();
        {
                /* Uncaught error while executing portal: mark it dead */
                MarkPortalFailed(portal);

                /* Restore global vars and propagate error */
                ActivePortal = saveActivePortal;
                CurrentResourceOwner = saveResourceOwner;
                PortalContext = savePortalContext;

                PG_RE_THROW();
        }
        PG_END_TRY();

        MemoryContextSwitchTo(oldContext);

        ActivePortal = saveActivePortal;
        CurrentResourceOwner = saveResourceOwner;
        PortalContext = savePortalContext;

        portal->status = PORTAL_READY;
}

/*
 * PortalSetResultFormat
 *              Select the format codes for a portal's output.
 *
 * This must be run after PortalStart for a portal that will be read by
 * a DestRemote or DestRemoteExecute destination.  It is not presently needed
 * for other destination types.
 *
 * formats[] is the client format request, as per Bind message conventions.
 */
void
PortalSetResultFormat(Portal portal, int nFormats, int16 *formats)
{
        int                     natts;
        int                     i;

        /* Do nothing if portal won't return tuples */
        if (portal->tupDesc == NULL)
                return;
        natts = portal->tupDesc->natts;
        portal->formats = (int16 *)
                MemoryContextAlloc(portal->portalContext,
                                                   natts * sizeof(int16));
        if (nFormats > 1)
        {
                /* format specified for each column */
                if (nFormats != natts)
                        ereport(ERROR,
                                        (errcode(ERRCODE_PROTOCOL_VIOLATION),
                                         errmsg("bind message has %d result formats but query has %d columns",
                                                        nFormats, natts)));
                memcpy(portal->formats, formats, natts * sizeof(int16));
        }
        else if (nFormats > 0)
        {
                /* single format specified, use for all columns */
                int16           format1 = formats[0];

                for (i = 0; i < natts; i++)
                        portal->formats[i] = format1;
        }
        else
        {
                /* use default format for all columns */
                for (i = 0; i < natts; i++)
                        portal->formats[i] = 0;
        }
}

/*
 * PortalRun
