PortalRunSelect(Portal portal,
                                bool forward,
                                long count,
                                DestReceiver *dest)
{
        QueryDesc  *queryDesc;
        ScanDirection direction;
        uint64          nprocessed;

        /*
         * NB: queryDesc will be NULL if we are fetching from a held cursor or a
         * completed utility query; can't use it in that path.
         */
        queryDesc = portal->queryDesc;

        /* Caller messed up if we have neither a ready query nor held data. */
        Assert(queryDesc || portal->holdStore);

        /*
         * Force the queryDesc destination to the right thing.  This supports
         * MOVE, for example, which will pass in dest = DestNone.  This is okay to
         * change as long as we do it on every fetch.  (The Executor must not
         * assume that dest never changes.)
         */
        if (queryDesc)
                queryDesc->dest = dest;

        /*
         * Determine which direction to go in, and check to see if we're already
         * at the end of the available tuples in that direction.  If so, set the
         * direction to NoMovement to avoid trying to fetch any tuples.  (This
         * check exists because not all plan node types are robust about being
         * called again if they've already returned NULL once.)  Then call the
         * executor (we must not skip this, because the destination needs to see a
         * setup and shutdown even if no tuples are available).  Finally, update
         * the portal position state depending on the number of tuples that were
         * retrieved.
         */
        if (forward)
        {
                if (portal->atEnd || count <= 0)
                {
                        direction = NoMovementScanDirection;
                        count = 0;                      /* don't pass negative count to executor */
                }
                else
                        direction = ForwardScanDirection;

                /* In the executor, zero count processes all rows */
                if (count == FETCH_ALL)
                        count = 0;

                if (portal->holdStore)
                        nprocessed = RunFromStore(portal, direction, (uint64) count, dest);
                else
                {
                        PushActiveSnapshot(queryDesc->snapshot);
                        ExecutorRun(queryDesc, direction, (uint64) count);
                        nprocessed = queryDesc->estate->es_processed;
                        PopActiveSnapshot();
                }

                if (!ScanDirectionIsNoMovement(direction))
                {
                        if (nprocessed > 0)
                                portal->atStart = false;        /* OK to go backward now */
                        if (count == 0 || nprocessed < (uint64) count)
                                portal->atEnd = true;   /* we retrieved 'em all */
                        portal->portalPos += nprocessed;
                }
        }
        else
        {
                if (portal->cursorOptions & CURSOR_OPT_NO_SCROLL)
                        ereport(ERROR,
                                        (errcode(ERRCODE_OBJECT_NOT_IN_PREREQUISITE_STATE),
                                         errmsg("cursor can only scan forward"),

pg_parse_query(const char *query_string)
{
        List       *raw_parsetree_list;

        TRACE_POSTGRESQL_QUERY_PARSE_START(query_string);

        if (log_parser_stats)
                ResetUsage();

        raw_parsetree_list = raw_parser(query_string, RAW_PARSE_DEFAULT);

        if (log_parser_stats)
                ShowUsage("PARSER STATISTICS");

#ifdef DEBUG_NODE_TESTS_ENABLED

        /* Optional debugging check: pass raw parsetrees through copyObject() */
        if (Debug_copy_parse_plan_trees)
        {
                List       *new_list = copyObject(raw_parsetree_list);

                /* This checks both copyObject() and the equal() routines... */
                if (!equal(new_list, raw_parsetree_list))
                        elog(WARNING, "copyObject() failed to produce an equal raw parse tree");
                else
                        raw_parsetree_list = new_list;
        }

        /*
         * Optional debugging check: pass raw parsetrees through
         * outfuncs/readfuncs
         */
        if (Debug_write_read_parse_plan_trees)
        {
                char       *str = nodeToStringWithLocations(raw_parsetree_list);
                List       *new_list = stringToNodeWithLocations(str);

                pfree(str);
                /* This checks both outfuncs/readfuncs and the equal() routines... */
                if (!equal(new_list, raw_parsetree_list))
                        elog(WARNING, "outfuncs/readfuncs failed to produce an equal raw parse tree");
                else
                        raw_parsetree_list = new_list;
        }

#endif                                                  /* DEBUG_NODE_TESTS_ENABLED */

        TRACE_POSTGRESQL_QUERY_PARSE_DONE(query_string);

        return raw_parsetree_list;
}

