 */
List *
raw_parser(const char *str, RawParseMode mode)
{
        core_yyscan_t yyscanner;
        base_yy_extra_type yyextra;
        int                     yyresult;

        /* initialize the flex scanner */
        yyscanner = scanner_init(str, &yyextra.core_yy_extra,
                                                         &ScanKeywords, ScanKeywordTokens);

        /* base_yylex() only needs us to initialize the lookahead token, if any */
        if (mode == RAW_PARSE_DEFAULT)
                yyextra.have_lookahead = false;
        else
        {
                /* this array is indexed by RawParseMode enum */
                static const int mode_token[] = {
                        [RAW_PARSE_DEFAULT] = 0,
                        [RAW_PARSE_TYPE_NAME] = MODE_TYPE_NAME,
                        [RAW_PARSE_PLPGSQL_EXPR] = MODE_PLPGSQL_EXPR,
                        [RAW_PARSE_PLPGSQL_ASSIGN1] = MODE_PLPGSQL_ASSIGN1,
                        [RAW_PARSE_PLPGSQL_ASSIGN2] = MODE_PLPGSQL_ASSIGN2,
                        [RAW_PARSE_PLPGSQL_ASSIGN3] = MODE_PLPGSQL_ASSIGN3,
                };

                yyextra.have_lookahead = true;
                yyextra.lookahead_token = mode_token[mode];
                yyextra.lookahead_yylloc = 0;
                yyextra.lookahead_end = NULL;
        }

        /* initialize the bison parser */
        parser_init(&yyextra);

        /* Parse! */
        yyresult = base_yyparse(yyscanner);

        /* Clean up (release memory) */
        scanner_finish(yyscanner);

        if (yyresult)                           /* error */
                return NIL;

        return yyextra.parsetree;
}


/*
 * Intermediate filter between parser and core lexer (core_yylex in scan.l).
 *
 * This filter is needed because in some cases the standard SQL grammar
 * requires more than one token lookahead.  We reduce these cases to one-token
 * lookahead by replacing tokens here, in order to keep the grammar LALR(1).
 *
 * Using a filter is simpler than trying to recognize multiword tokens
 * directly in scan.l, because we'd have to allow for comments between the
 * words.  Furthermore it's not clear how to do that without re-introducing
 * scanner backtrack, which would cost more performance than this filter
 * layer does.
 *
 * We also use this filter to convert UIDENT and USCONST sequences into
 * plain IDENT and SCONST tokens.  While that could be handled by additional
 * productions in the main grammar, it's more efficient to do it like this.
 *
 * The filter also provides a convenient place to translate between
 * the core_YYSTYPE and YYSTYPE representations (which are really the
 * same thing anyway, but notationally they're different).
 */
int
base_yylex(YYSTYPE *lvalp, YYLTYPE *llocp, core_yyscan_t yyscanner)
{
        base_yy_extra_type *yyextra = pg_yyget_extra(yyscanner);
        int                     cur_token;
        int                     next_token;
        int                     cur_token_length;
        YYLTYPE         cur_yylloc;

        /* Get next token --- we might already have it */
        if (yyextra->have_lookahead)

attcollid = att_tup->attcollation;
        if (attcollid && attcollid != exprCollation(defexpr))
        {
                CollateExpr *ce = makeNode(CollateExpr);

                ce->arg = (Expr *) defexpr;
                ce->collOid = attcollid;
                ce->location = -1;

                defexpr = (Node *) ce;
        }

        return defexpr;
}


/*
 * QueryRewrite -
 *        Primary entry point to the query rewriter.
 *        Rewrite one query via query rewrite system, possibly returning 0
 *        or many queries.
 *
 * NOTE: the parsetree must either have come straight from the parser,
 * or have been scanned by AcquireRewriteLocks to acquire suitable locks.
 */
List *
QueryRewrite(Query *parsetree)
{
        int64           input_query_id = parsetree->queryId;
        List       *querylist;
        List       *results;
        ListCell   *l;
        CmdType         origCmdType;
        bool            foundOriginalQuery;
        Query      *lastInstead;

        /*
         * This function is only applied to top-level original queries
         */
        Assert(parsetree->querySource == QSRC_ORIGINAL);
        Assert(parsetree->canSetTag);

        /*
         * Step 1
         *
         * Apply all non-SELECT rules possibly getting 0 or many queries
         */
        querylist = RewriteQuery(parsetree, NIL, 0, 0);

        /*
         * Step 2
         *
         * Apply all the RIR rules on each query
         *
         * This is also a handy place to mark each query with the original queryId
         */
        results = NIL;
        foreach(l, querylist)
        {
                Query      *query = (Query *) lfirst(l);

                query = fireRIRrules(query, NIL);

                query->queryId = input_query_id;

                results = lappend(results, query);
        }

        /*
         * Step 3
         *
         * Determine which, if any, of the resulting queries is supposed to set
         * the command-result tag; and update the canSetTag fields accordingly.
         *
         * If the original query is still in the list, it sets the command tag.
         * Otherwise, the last INSTEAD query of the same kind as the original is
         * allowed to set the tag.  (Note these rules can leave us with no query
         * setting the tag.  The tcop code has to cope with this by setting up a
         * default tag based on the original un-rewritten query.)
         *
         * The Asserts verify that at most one query in the result list is marked
         * canSetTag.  If we aren't checking asserts, we can fall out of the loop
         * as soon as we find the original query.
         */
        origCmdType = parsetree->commandType;
        foundOriginalQuery = false;
        lastInstead = NULL;

        foreach(l, results)
        {
                Query      *query = (Query *) lfirst(l);

                if (query->querySource == QSRC_ORIGINAL)
                {
                        Assert(query->canSetTag);
                        Assert(!foundOriginalQuery);
                        foundOriginalQuery = true;
#ifndef USE_ASSERT_CHECKING
                        break;
#endif
                }

* standard_planner().
 *
 * Note to plugin authors: standard_planner() scribbles on its Query input,
 * so you'd better copy that data structure if you want to plan more than once.
 *
 *****************************************************************************/
PlannedStmt *
planner(Query *parse, const char *query_string, int cursorOptions,
                ParamListInfo boundParams)
{
        PlannedStmt *result;

        if (planner_hook)
                result = (*planner_hook) (parse, query_string, cursorOptions, boundParams);
        else
                result = standard_planner(parse, query_string, cursorOptions, boundParams);

        pgstat_report_plan_id(result->planId, false);

        return result;
}

PlannedStmt *
standard_planner(Query *parse, const char *query_string, int cursorOptions,
                                 ParamListInfo boundParams)
{
        PlannedStmt *result;
        PlannerGlobal *glob;
        double          tuple_fraction;
        PlannerInfo *root;
        RelOptInfo *final_rel;
        Path       *best_path;
        Plan       *top_plan;
        ListCell   *lp,
                           *lr;

        /*
         * Set up global state for this planner invocation.  This data is needed
         * across all levels of sub-Query that might exist in the given command,
         * so we keep it in a separate struct that's linked to by each per-Query
         * PlannerInfo.
         */
        glob = makeNode(PlannerGlobal);

        glob->boundParams = boundParams;
        glob->subplans = NIL;
        glob->subpaths = NIL;
        glob->subroots = NIL;
        glob->rewindPlanIDs = NULL;
        glob->finalrtable = NIL;
        glob->allRelids = NULL;
        glob->prunableRelids = NULL;
        glob->finalrteperminfos = NIL;
        glob->finalrowmarks = NIL;
        glob->resultRelations = NIL;
        glob->appendRelations = NIL;
        glob->partPruneInfos = NIL;
        glob->relationOids = NIL;
        glob->invalItems = NIL;
        glob->paramExecTypes = NIL;
        glob->lastPHId = 0;
        glob->lastRowMarkId = 0;
        glob->lastPlanNodeId = 0;
        glob->transientPlan = false;
        glob->dependsOnRole = false;
        glob->partition_directory = NULL;

        /*
         * Assess whether it's feasible to use parallel mode for this query. We
         * can't do this in a standalone backend, or if the command will try to
         * modify any data, or if this is a cursor operation, or if GUCs are set
         * to values that don't permit parallelism, or if parallel-unsafe
         * functions are present in the query tree.
         *
         * (Note that we do allow CREATE TABLE AS, SELECT INTO, and CREATE
         * MATERIALIZED VIEW to use parallel plans, but this is safe only because
         * the command is writing into a completely new table which workers won't
         * be able to see.  If the workers could see the table, the fact that
         * group locking would cause them to ignore the leader's heavyweight GIN
         * page locks would make this unsafe.  We'll have to fix that somehow if
         * we want to allow parallel inserts in general; updates and deletes have
         * additional problems especially around combo CIDs.)
         *
         * For now, we don't try to use parallel mode if we're running inside a
         * parallel worker.  We might eventually be able to relax this
         * restriction, but for now it seems best not to have parallel workers
         * trying to create their own parallel workers.
         */
        if ((cursorOptions & CURSOR_OPT_PARALLEL_OK) != 0 &&
                IsUnderPostmaster &&
                parse->commandType == CMD_SELECT &&
                !parse->hasModifyingCTE &&
                max_parallel_workers_per_gather > 0 &&
                !IsParallelWorker())
        {
                /* all the cheap tests pass, so scan the query tree */
                glob->maxParallelHazard = max_parallel_hazard(parse);
                glob->parallelModeOK = (glob->maxParallelHazard != PROPARALLEL_UNSAFE);
        }
        else
        {
                /* skip the query tree scan, just assume it's unsafe */
                glob->maxParallelHazard = PROPARALLEL_UNSAFE;
                glob->parallelModeOK = false;
        }

        /*
         * glob->parallelModeNeeded is normally set to false here and changed to
         * true during plan creation if a Gather or Gather Merge plan is actually
         * created (cf. create_gather_plan, create_gather_merge_plan).
         *
         * However, if debug_parallel_query = on or debug_parallel_query =
         * regress, then we impose parallel mode whenever it's safe to do so, even
         * if the final plan doesn't use parallelism.  It's not safe to do so if
         * the query contains anything parallel-unsafe; parallelModeOK will be
         * false in that case.  Note that parallelModeOK can't change after this
         * point. Otherwise, everything in the query is either parallel-safe or
         * parallel-restricted, and in either case it should be OK to impose
         * parallel-mode restrictions.  If that ends up breaking something, then
         * either some function the user included in the query is incorrectly
         * labeled as parallel-safe or parallel-restricted when in reality it's
         * parallel-unsafe, or else the query planner itself has a bug.
         */
        glob->parallelModeNeeded = glob->parallelModeOK &&
                (debug_parallel_query != DEBUG_PARALLEL_OFF);

        /* Determine what fraction of the plan is likely to be scanned */
        if (cursorOptions & CURSOR_OPT_FAST_PLAN)
        {
                /*
                 * We have no real idea how many tuples the user will ultimately FETCH
                 * from a cursor, but it is often the case that he doesn't want 'em
                 * all, or would prefer a fast-start plan anyway so that he can
                 * process some of the tuples sooner.  Use a GUC parameter to decide
                 * what fraction to optimize for.
                 */
                tuple_fraction = cursor_tuple_fraction;

                /*
                 * We document cursor_tuple_fraction as simply being a fraction, which
                 * means the edge cases 0 and 1 have to be treated specially here.  We
                 * convert 1 to 0 ("all the tuples") and 0 to a very small fraction.
                 */
                if (tuple_fraction >= 1.0)
                        tuple_fraction = 0.0;
                else if (tuple_fraction <= 0.0)
                        tuple_fraction = 1e-10;
        }
        else
        {
                /* Default assumption is we need all the tuples */
                tuple_fraction = 0.0;
        }

        /* primary planning entry point (may recurse for subqueries) */
        root = subquery_planner(glob, parse, NULL, false, tuple_fraction, NULL);

        /* Select best Path and turn it into a Plan */
        final_rel = fetch_upper_rel(root, UPPERREL_FINAL, NULL);
        best_path = get_cheapest_fractional_path(final_rel, tuple_fraction);

top_plan = create_plan(root, best_path);

        /*
         * If creating a plan for a scrollable cursor, make sure it can run
         * backwards on demand.  Add a Material node at the top at need.
         */
        if (cursorOptions & CURSOR_OPT_SCROLL)
        {
                if (!ExecSupportsBackwardScan(top_plan))
                        top_plan = materialize_finished_plan(top_plan);
        }

        /*
         * Optionally add a Gather node for testing purposes, provided this is
         * actually a safe thing to do.
         *
         * We can add Gather even when top_plan has parallel-safe initPlans, but
         * then we have to move the initPlans to the Gather node because of
         * SS_finalize_plan's limitations.  That would cause cosmetic breakage of
         * regression tests when debug_parallel_query = regress, because initPlans
         * that would normally appear on the top_plan move to the Gather, causing
         * them to disappear from EXPLAIN output.  That doesn't seem worth kluging
         * EXPLAIN to hide, so skip it when debug_parallel_query = regress.
         */
        if (debug_parallel_query != DEBUG_PARALLEL_OFF &&
                top_plan->parallel_safe &&
                (top_plan->initPlan == NIL ||
                 debug_parallel_query != DEBUG_PARALLEL_REGRESS))
        {
                Gather     *gather = makeNode(Gather);
                Cost            initplan_cost;
                bool            unsafe_initplans;

                gather->plan.targetlist = top_plan->targetlist;
                gather->plan.qual = NIL;
                gather->plan.lefttree = top_plan;
                gather->plan.righttree = NULL;
                gather->num_workers = 1;
                gather->single_copy = true;
                gather->invisible = (debug_parallel_query == DEBUG_PARALLEL_REGRESS);

                /* Transfer any initPlans to the new top node */
                gather->plan.initPlan = top_plan->initPlan;
                top_plan->initPlan = NIL;

                /*
                 * Since this Gather has no parallel-aware descendants to signal to,
                 * we don't need a rescan Param.
                 */
                gather->rescan_param = -1;

                /*
                 * Ideally we'd use cost_gather here, but setting up dummy path data
                 * to satisfy it doesn't seem much cleaner than knowing what it does.
                 */
                gather->plan.startup_cost = top_plan->startup_cost +
                        parallel_setup_cost;
                gather->plan.total_cost = top_plan->total_cost +
                        parallel_setup_cost + parallel_tuple_cost * top_plan->plan_rows;
                gather->plan.plan_rows = top_plan->plan_rows;
                gather->plan.plan_width = top_plan->plan_width;
                gather->plan.parallel_aware = false;
                gather->plan.parallel_safe = false;

                /*
                 * Delete the initplans' cost from top_plan.  We needn't add it to the
                 * Gather node, since the above coding already included it there.
                 */
                SS_compute_initplan_cost(gather->plan.initPlan,
                                                                 &initplan_cost, &unsafe_initplans);
                top_plan->startup_cost -= initplan_cost;
                top_plan->total_cost -= initplan_cost;

                /* use parallel mode for parallel plans. */
                root->glob->parallelModeNeeded = true;

                top_plan = &gather->plan;
        }

        /*
         * If any Params were generated, run through the plan tree and compute
         * each plan node's extParam/allParam sets.  Ideally we'd merge this into
         * set_plan_references' tree traversal, but for now it has to be separate
         * because we need to visit subplans before not after main plan.
         */
        if (glob->paramExecTypes != NIL)
        {
                Assert(list_length(glob->subplans) == list_length(glob->subroots));
                forboth(lp, glob->subplans, lr, glob->subroots)
                {
                        Plan       *subplan = (Plan *) lfirst(lp);
                        PlannerInfo *subroot = lfirst_node(PlannerInfo, lr);

                        SS_finalize_plan(subroot, subplan);
                }
                SS_finalize_plan(root, top_plan);
        }

        /* final cleanup of the plan */
        Assert(glob->finalrtable == NIL);
        Assert(glob->finalrteperminfos == NIL);
        Assert(glob->finalrowmarks == NIL);
        Assert(glob->resultRelations == NIL);
        Assert(glob->appendRelations == NIL);
        top_plan = set_plan_references(root, top_plan);
        /* ... and the subplans (both regular subplans and initplans) */
        Assert(list_length(glob->subplans) == list_length(glob->subroots));
        forboth(lp, glob->subplans, lr, glob->subroots)
        {
                Plan       *subplan = (Plan *) lfirst(lp);
                PlannerInfo *subroot = lfirst_node(PlannerInfo, lr);

                lfirst(lp) = set_plan_references(subroot, subplan);
        }

        /* build the PlannedStmt result */
        result = makeNode(PlannedStmt);

        result->commandType = parse->commandType;
        result->queryId = parse->queryId;
        result->hasReturning = (parse->returningList != NIL);
        result->hasModifyingCTE = parse->hasModifyingCTE;
        result->canSetTag = parse->canSetTag;
        result->transientPlan = glob->transientPlan;
        result->dependsOnRole = glob->dependsOnRole;
        result->parallelModeNeeded = glob->parallelModeNeeded;
        result->planTree = top_plan;
        result->partPruneInfos = glob->partPruneInfos;
        result->rtable = glob->finalrtable;
        result->unprunableRelids = bms_difference(glob->allRelids,
                                                                                          glob->prunableRelids);
        result->permInfos = glob->finalrteperminfos;
        result->resultRelations = glob->resultRelations;
        result->appendRelations = glob->appendRelations;
        result->subplans = glob->subplans;
        result->rewindPlanIDs = glob->rewindPlanIDs;
        result->rowMarks = glob->finalrowmarks;
        result->relationOids = glob->relationOids;
        result->invalItems = glob->invalItems;
        result->paramExecTypes = glob->paramExecTypes;
        /* utilityStmt should be null, but we might as well copy it */
        result->utilityStmt = parse->utilityStmt;
        result->stmt_location = parse->stmt_location;
        result->stmt_len = parse->stmt_len;

        result->jitFlags = PGJIT_NONE;
        if (jit_enabled && jit_above_cost >= 0 &&
                top_plan->total_cost > jit_above_cost)
        {
                result->jitFlags |= PGJIT_PERFORM;

                /*
                 * Decide how much effort should be put into generating better code.
                 */
                if (jit_optimize_above_cost >= 0 &&
                        top_plan->total_cost > jit_optimize_above_cost)
                        result->jitFlags |= PGJIT_OPT3;
                if (jit_inline_above_cost >= 0 &&
                        top_plan->total_cost > jit_inline_above_cost)
                        result->jitFlags |= PGJIT_INLINE;

                /*
                 * Decide which operations should be JITed.
                 */
                if (jit_expressions)
                        result->jitFlags |= PGJIT_EXPR;
                if (jit_tuple_deforming)
                        result->jitFlags |= PGJIT_DEFORM;
        }

        if (glob->partition_directory != NULL)
                DestroyPartitionDirectory(glob->partition_directory);

        return result;
}


/*--------------------
 * subquery_planner
 *        Invokes the planner on a subquery.  We recurse to here for each

subquery_planner(PlannerGlobal *glob, Query *parse, PlannerInfo *parent_root,
                                 bool hasRecursion, double tuple_fraction,
                                 SetOperationStmt *setops)
{
        PlannerInfo *root;
        List       *newWithCheckOptions;
        List       *newHaving;
        bool            hasOuterJoins;
        bool            hasResultRTEs;
        RelOptInfo *final_rel;
        ListCell   *l;

        /* Create a PlannerInfo data structure for this subquery */
        root = makeNode(PlannerInfo);
        root->parse = parse;
        root->glob = glob;
        root->query_level = parent_root ? parent_root->query_level + 1 : 1;
        root->parent_root = parent_root;
        root->plan_params = NIL;
        root->outer_params = NULL;
        root->planner_cxt = CurrentMemoryContext;
        root->init_plans = NIL;
        root->cte_plan_ids = NIL;
        root->multiexpr_params = NIL;
        root->join_domains = NIL;
        root->eq_classes = NIL;
        root->ec_merging_done = false;
        root->last_rinfo_serial = 0;
        root->all_result_relids =
                parse->resultRelation ? bms_make_singleton(parse->resultRelation) : NULL;
        root->leaf_result_relids = NULL;        /* we'll find out leaf-ness later */
        root->append_rel_list = NIL;
        root->row_identity_vars = NIL;
        root->rowMarks = NIL;
        memset(root->upper_rels, 0, sizeof(root->upper_rels));
        memset(root->upper_targets, 0, sizeof(root->upper_targets));
        root->processed_groupClause = NIL;
        root->processed_distinctClause = NIL;
        root->processed_tlist = NIL;
        root->update_colnos = NIL;
        root->grouping_map = NULL;
        root->minmax_aggs = NIL;
        root->qual_security_level = 0;
        root->hasPseudoConstantQuals = false;
        root->hasAlternativeSubPlans = false;
        root->placeholdersFrozen = false;
        root->hasRecursion = hasRecursion;
        if (hasRecursion)
                root->wt_param_id = assign_special_exec_param(root);
        else
                root->wt_param_id = -1;
        root->non_recursive_path = NULL;
        root->partColsUpdated = false;

        /*
         * Create the top-level join domain.  This won't have valid contents until
         * deconstruct_jointree fills it in, but the node needs to exist before
         * that so we can build EquivalenceClasses referencing it.
         */
        root->join_domains = list_make1(makeNode(JoinDomain));

        /*
         * If there is a WITH list, process each WITH query and either convert it
         * to RTE_SUBQUERY RTE(s) or build an initplan SubPlan structure for it.
         */
        if (parse->cteList)
                SS_process_ctes(root);

        /*
         * If it's a MERGE command, transform the joinlist as appropriate.
         */
        transform_MERGE_to_join(parse);

        /*
         * If the FROM clause is empty, replace it with a dummy RTE_RESULT RTE, so
         * that we don't need so many special cases to deal with that situation.
         */
        replace_empty_jointree(parse);

        /*
         * Look for ANY and EXISTS SubLinks in WHERE and JOIN/ON clauses, and try
         * to transform them into joins.  Note that this step does not descend
         * into subqueries; if we pull up any subqueries below, their SubLinks are
         * processed just before pulling them up.
         */
        if (parse->hasSubLinks)
                pull_up_sublinks(root);

        /*
         * Scan the rangetable for function RTEs, do const-simplification on them,
         * and then inline them if possible (producing subqueries that might get
         * pulled up next).  Recursion issues here are handled in the same way as
         * for SubLinks.
         */
        preprocess_function_rtes(root);

        /*
         * Scan the rangetable for relations with virtual generated columns, and
         * replace all Var nodes in the query that reference these columns with
         * the generation expressions.  Recursion issues here are handled in the
         * same way as for SubLinks.
         */
        parse = root->parse = expand_virtual_generated_columns(root);

        /*
         * Check to see if any subqueries in the jointree can be merged into this
         * query.
         */
        pull_up_subqueries(root);

        /*
         * If this is a simple UNION ALL query, flatten it into an appendrel. We
         * do this now because it requires applying pull_up_subqueries to the leaf
         * queries of the UNION ALL, which weren't touched above because they
         * weren't referenced by the jointree (they will be after we do this).
         */
        if (parse->setOperations)
                flatten_simple_union_all(root);

        /*
         * Survey the rangetable to see what kinds of entries are present.  We can
         * skip some later processing if relevant SQL features are not used; for
         * example if there are no JOIN RTEs we can avoid the expense of doing
         * flatten_join_alias_vars().  This must be done after we have finished
         * adding rangetable entries, of course.  (Note: actually, processing of
         * inherited or partitioned rels can cause RTEs for their child tables to
         * get added later; but those must all be RTE_RELATION entries, so they
         * don't invalidate the conclusions drawn here.)
         */
        root->hasJoinRTEs = false;
        root->hasLateralRTEs = false;
        root->group_rtindex = 0;
        hasOuterJoins = false;
        hasResultRTEs = false;
        foreach(l, parse->rtable)
        {
                RangeTblEntry *rte = lfirst_node(RangeTblEntry, l);

                switch (rte->rtekind)
                {
                        case RTE_RELATION:
                                if (rte->inh)
                                {
                                        /*
                                         * Check to see if the relation actually has any children;
                                         * if not, clear the inh flag so we can treat it as a
                                         * plain base relation.
                                         *
                                         * Note: this could give a false-positive result, if the
                                         * rel once had children but no longer does.  We used to

InitPlan(QueryDesc *queryDesc, int eflags)
{
        CmdType         operation = queryDesc->operation;
        PlannedStmt *plannedstmt = queryDesc->plannedstmt;
        Plan       *plan = plannedstmt->planTree;
        List       *rangeTable = plannedstmt->rtable;
        EState     *estate = queryDesc->estate;
        PlanState  *planstate;
        TupleDesc       tupType;
        ListCell   *l;
        int                     i;

        /*
         * Do permissions checks
         */
        ExecCheckPermissions(rangeTable, plannedstmt->permInfos, true);

        /*
         * initialize the node's execution state
         */
        ExecInitRangeTable(estate, rangeTable, plannedstmt->permInfos,
                                           bms_copy(plannedstmt->unprunableRelids));

        estate->es_plannedstmt = plannedstmt;
        estate->es_part_prune_infos = plannedstmt->partPruneInfos;

        /*
         * Perform runtime "initial" pruning to identify which child subplans,
         * corresponding to the children of plan nodes that contain
         * PartitionPruneInfo such as Append, will not be executed. The results,
         * which are bitmapsets of indexes of the child subplans that will be
         * executed, are saved in es_part_prune_results.  These results correspond
         * to each PartitionPruneInfo entry, and the es_part_prune_results list is
         * parallel to es_part_prune_infos.
         */
        ExecDoInitialPruning(estate);

        /*
         * Next, build the ExecRowMark array from the PlanRowMark(s), if any.
         */
        if (plannedstmt->rowMarks)
        {
                estate->es_rowmarks = (ExecRowMark **)
                        palloc0(estate->es_range_table_size * sizeof(ExecRowMark *));
                foreach(l, plannedstmt->rowMarks)
                {
                        PlanRowMark *rc = (PlanRowMark *) lfirst(l);
                        RangeTblEntry *rte = exec_rt_fetch(rc->rti, estate);
                        Oid                     relid;
                        Relation        relation;
                        ExecRowMark *erm;

                        /* ignore "parent" rowmarks; they are irrelevant at runtime */
                        if (rc->isParent)
                                continue;

                        /*
                         * Also ignore rowmarks belonging to child tables that have been
                         * pruned in ExecDoInitialPruning().
                         */
                        if (rte->rtekind == RTE_RELATION &&
                                !bms_is_member(rc->rti, estate->es_unpruned_relids))
                                continue;

                        /* get relation's OID (will produce InvalidOid if subquery) */
                        relid = rte->relid;

                        /* open relation, if we need to access it for this mark type */
                        switch (rc->markType)
                        {
                                case ROW_MARK_EXCLUSIVE:
                                case ROW_MARK_NOKEYEXCLUSIVE:
                                case ROW_MARK_SHARE:
                                case ROW_MARK_KEYSHARE:
                                case ROW_MARK_REFERENCE:
                                        relation = ExecGetRangeTableRelation(estate, rc->rti, false);
                                        break;
                                case ROW_MARK_COPY:
                                        /* no physical table access is required */
                                        relation = NULL;
                                        break;
                                default:
                                        elog(ERROR, "unrecognized markType: %d", rc->markType);
                                        relation = NULL;        /* keep compiler quiet */
                                        break;
                        }

                        /* Check that relation is a legal target for marking */
                        if (relation)
                                CheckValidRowMarkRel(relation, rc->markType);

                        erm = (ExecRowMark *) palloc(sizeof(ExecRowMark));
                        erm->relation = relation;
                        erm->relid = relid;
                        erm->rti = rc->rti;
                        erm->prti = rc->prti;
                        erm->rowmarkId = rc->rowmarkId;
                        erm->markType = rc->markType;
                        erm->strength = rc->strength;
                        erm->waitPolicy = rc->waitPolicy;
                        erm->ermActive = false;
                        ItemPointerSetInvalid(&(erm->curCtid));
                        erm->ermExtra = NULL;

                        Assert(erm->rti > 0 && erm->rti <= estate->es_range_table_size &&
                                   estate->es_rowmarks[erm->rti - 1] == NULL);

                        estate->es_rowmarks[erm->rti - 1] = erm;
                }
        }

        /*
         * Initialize the executor's tuple table to empty.
         */
        estate->es_tupleTable = NIL;

        /* signal that this EState is not used for EPQ */
        estate->es_epq_active = NULL;

        /*
         * Initialize private state information for each SubPlan.  We must do this
         * before running ExecInitNode on the main query tree, since
         * ExecInitSubPlan expects to be able to find these entries.
         */
        Assert(estate->es_subplanstates == NIL);
        i = 1;                                          /* subplan indices count from 1 */
        foreach(l, plannedstmt->subplans)
        {
                Plan       *subplan = (Plan *) lfirst(l);
                PlanState  *subplanstate;
                int                     sp_eflags;

                /*
                 * A subplan will never need to do BACKWARD scan nor MARK/RESTORE. If
                 * it is a parameterless subplan (not initplan), we suggest that it be
                 * prepared to handle REWIND efficiently; otherwise there is no need.
                 */
                sp_eflags = eflags
                        & ~(EXEC_FLAG_REWIND | EXEC_FLAG_BACKWARD | EXEC_FLAG_MARK);
                if (bms_is_member(i, plannedstmt->rewindPlanIDs))
                        sp_eflags |= EXEC_FLAG_REWIND;

                subplanstate = ExecInitNode(subplan, estate, sp_eflags);

                estate->es_subplanstates = lappend(estate->es_subplanstates,
                                                                                   subplanstate);

                i++;
        }

        /*
         * Initialize the private state information for all the nodes in the query
         * tree.  This opens files, allocates storage and leaves us ready to start
         * processing tuples.
         */

*/
        planstate = ExecInitNode(plan, estate, eflags);

        /*
         * Get the tuple descriptor describing the type of tuples to return.
         */
        tupType = ExecGetResultType(planstate);

        /*
         * Initialize the junk filter if needed.  SELECT queries need a filter if
         * there are any junk attrs in the top-level tlist.
         */
        if (operation == CMD_SELECT)
        {
                bool            junk_filter_needed = false;
                ListCell   *tlist;

                foreach(tlist, plan->targetlist)
                {
                        TargetEntry *tle = (TargetEntry *) lfirst(tlist);

                        if (tle->resjunk)
                        {
                                junk_filter_needed = true;
                                break;
                        }
                }

                if (junk_filter_needed)
                {
                        JunkFilter *j;
                        TupleTableSlot *slot;

                        slot = ExecInitExtraTupleSlot(estate, NULL, &TTSOpsVirtual);
                        j = ExecInitJunkFilter(planstate->plan->targetlist,
                                                                   slot);
                        estate->es_junkFilter = j;

                        /* Want to return the cleaned tuple type */
                        tupType = j->jf_cleanTupType;
                }
        }

        queryDesc->tupDesc = tupType;
        queryDesc->planstate = planstate;
}

/*
 * Check that a proposed result relation is a legal target for the operation
 *
 * Generally the parser and/or planner should have noticed any such mistake
 * already, but let's make sure.
 *
 * For INSERT ON CONFLICT, the result relation is required to support the
 * onConflictAction, regardless of whether a conflict actually occurs.
 *
 * For MERGE, mergeActions is the list of actions that may be performed.  The
 * result relation is required to support every action, regardless of whether
 * or not they are all executed.
 *
 * Note: when changing this function, you probably also need to look at

exec_simple_query(const char *query_string)
{
        CommandDest dest = whereToSendOutput;
        MemoryContext oldcontext;
        List       *parsetree_list;
        ListCell   *parsetree_item;
        bool            save_log_statement_stats = log_statement_stats;
        bool            was_logged = false;
        bool            use_implicit_block;
        char            msec_str[32];

        /*
         * Report query to various monitoring facilities.
         */
        debug_query_string = query_string;

        pgstat_report_activity(STATE_RUNNING, query_string);

        TRACE_POSTGRESQL_QUERY_START(query_string);

        /*
         * We use save_log_statement_stats so ShowUsage doesn't report incorrect
         * results because ResetUsage wasn't called.
         */
        if (save_log_statement_stats)
                ResetUsage();

        /*
         * Start up a transaction command.  All queries generated by the
         * query_string will be in this same command block, *unless* we find a
         * BEGIN/COMMIT/ABORT statement; we have to force a new xact command after
         * one of those, else bad things will happen in xact.c. (Note that this
         * will normally change current memory context.)
         */
        start_xact_command();

        /*
         * Zap any pre-existing unnamed statement.  (While not strictly necessary,
         * it seems best to define simple-Query mode as if it used the unnamed
         * statement and portal; this ensures we recover any storage used by prior
         * unnamed operations.)
         */
        drop_unnamed_stmt();

        /*
         * Switch to appropriate context for constructing parsetrees.
         */
        oldcontext = MemoryContextSwitchTo(MessageContext);

        /*
         * Do basic parsing of the query or queries (this should be safe even if
         * we are in aborted transaction state!)
         */
        parsetree_list = pg_parse_query(query_string);

        /* Log immediately if dictated by log_statement */
        if (check_log_statement(parsetree_list))
        {
                ereport(LOG,
                                (errmsg("statement: %s", query_string),
                                 errhidestmt(true),
                                 errdetail_execute(parsetree_list)));
                was_logged = true;
        }

        /*
         * Switch back to transaction context to enter the loop.
         */
        MemoryContextSwitchTo(oldcontext);

        /*
         * For historical reasons, if multiple SQL statements are given in a
         * single "simple Query" message, we execute them as a single transaction,
         * unless explicit transaction control commands are included to make
         * portions of the list be separate transactions.  To represent this
         * behavior properly in the transaction machinery, we use an "implicit"
         * transaction block.
         */
        use_implicit_block = (list_length(parsetree_list) > 1);

        /*
         * Run through the raw parsetree(s) and process each one.
         */
        foreach(parsetree_item, parsetree_list)
        {
                RawStmt    *parsetree = lfirst_node(RawStmt, parsetree_item);
                bool            snapshot_set = false;
                CommandTag      commandTag;
                QueryCompletion qc;
                MemoryContext per_parsetree_context = NULL;
                List       *querytree_list,
                                   *plantree_list;
                Portal          portal;
                DestReceiver *receiver;
                int16           format;
                const char *cmdtagname;
                size_t          cmdtaglen;

                pgstat_report_query_id(0, true);
                pgstat_report_plan_id(0, true);

                /*
                 * Get the command name for use in status display (it also becomes the
                 * default completion tag, down inside PortalRun).  Set ps_status and
                 * do any special start-of-SQL-command processing needed by the
                 * destination.
                 */
                commandTag = CreateCommandTag(parsetree->stmt);
                cmdtagname = GetCommandTagNameAndLen(commandTag, &cmdtaglen);

                set_ps_display_with_len(cmdtagname, cmdtaglen);

                BeginCommand(commandTag, dest);

                /*
                 * If we are in an aborted transaction, reject all commands except
                 * COMMIT/ABORT.  It is important that this test occur before we try
                 * to do parse analysis, rewrite, or planning, since all those phases
                 * try to do database accesses, which may fail in abort state. (It
                 * might be safe to allow some additional utility commands in this
                 * state, but not many...)
                 */
                if (IsAbortedTransactionBlockState() &&
                        !IsTransactionExitStmt(parsetree->stmt))
                        ereport(ERROR,
                                        (errcode(ERRCODE_IN_FAILED_SQL_TRANSACTION),
                                         errmsg("current transaction is aborted, "
                                                        "commands ignored until end of transaction block"),
                                         errdetail_abort()));

                /* Make sure we are in a transaction command */
                start_xact_command();

                /*
                 * If using an implicit transaction block, and we're not already in a
                 * transaction block, start an implicit block to force this statement
                 * to be grouped together with any following ones.  (We must do this
                 * each time through the loop; otherwise, a COMMIT/ROLLBACK in the
                 * list would cause later statements to not be grouped.)
                 */
                if (use_implicit_block)
                        BeginImplicitTransactionBlock();

                /* If we got a cancel signal in parsing or prior command, quit */
                CHECK_FOR_INTERRUPTS();

                /*
                 * Set up a snapshot if parse analysis/planning will need one.
                 */
                if (analyze_requires_snapshot(parsetree))
                {
                        PushActiveSnapshot(GetTransactionSnapshot());
                        snapshot_set = true;
                }

                /*
                 * OK to analyze, rewrite, and plan this query.
                 *
                 * Switch to appropriate context for constructing query and plan trees
                 * (these can't be in the transaction context, as that will get reset
                 * when the command is COMMIT/ROLLBACK).  If we have multiple
                 * parsetrees, we use a separate context for each one, so that we can
                 * free that memory before moving on to the next one.  But for the
                 * last (or only) parsetree, just use MessageContext, which will be
                 * reset shortly after completion anyway.  In event of an error, the
                 * per_parsetree_context will be deleted when MessageContext is reset.
                 */
                if (lnext(parsetree_list, parsetree_item) != NULL)
                {
                        per_parsetree_context =
                                AllocSetContextCreate(MessageContext,
                                                                          "per-parsetree message context",
                                                                          ALLOCSET_DEFAULT_SIZES);
                        oldcontext = MemoryContextSwitchTo(per_parsetree_context);
                }
                else
                        oldcontext = MemoryContextSwitchTo(MessageContext);

                querytree_list = pg_analyze_and_rewrite_fixedparams(parsetree, query_string,
                                                                                                                        NULL, 0, NULL);

                plantree_list = pg_plan_queries(querytree_list, query_string,
                                                                                CURSOR_OPT_PARALLEL_OK, NULL);

                /*
                 * Done with the snapshot used for parsing/planning.
                 *
                 * While it looks promising to reuse the same snapshot for query
                 * execution (at least for simple protocol), unfortunately it causes
                 * execution to use a snapshot that has been acquired before locking

* execution to use a snapshot that has been acquired before locking
                 * any of the tables mentioned in the query.  This creates user-
                 * visible anomalies, so refrain.  Refer to
                 * https://postgr.es/m/flat/5075D8DF.6050500@fuzzy.cz for details.
                 */
                if (snapshot_set)
                        PopActiveSnapshot();

                /* If we got a cancel signal in analysis or planning, quit */
                CHECK_FOR_INTERRUPTS();

                /*
                 * Create unnamed portal to run the query or queries in. If there
                 * already is one, silently drop it.
                 */
                portal = CreatePortal("", true, true);
                /* Don't display the portal in pg_cursors */
                portal->visible = false;

                /*
                 * We don't have to copy anything into the portal, because everything
                 * we are passing here is in MessageContext or the
                 * per_parsetree_context, and so will outlive the portal anyway.
                 */
                PortalDefineQuery(portal,
                                                  NULL,
                                                  query_string,
                                                  commandTag,
                                                  plantree_list,
                                                  NULL);

                /*
                 * Start the portal.  No parameters here.
                 */
                PortalStart(portal, NULL, 0, InvalidSnapshot);

                /*
                 * Select the appropriate output format: text unless we are doing a
                 * FETCH from a binary cursor.  (Pretty grotty to have to do this here
                 * --- but it avoids grottiness in other places.  Ah, the joys of
                 * backward compatibility...)
                 */
                format = 0;                             /* TEXT is default */
                if (IsA(parsetree->stmt, FetchStmt))
                {
                        FetchStmt  *stmt = (FetchStmt *) parsetree->stmt;

                        if (!stmt->ismove)
                        {
                                Portal          fportal = GetPortalByName(stmt->portalname);

                                if (PortalIsValid(fportal) &&
                                        (fportal->cursorOptions & CURSOR_OPT_BINARY))
                                        format = 1; /* BINARY */
                        }
                }
                PortalSetResultFormat(portal, 1, &format);

                /*
                 * Now we can create the destination receiver object.
                 */
                receiver = CreateDestReceiver(dest);
                if (dest == DestRemote)
                        SetRemoteDestReceiverParams(receiver, portal);

                /*
                 * Switch back to transaction context for execution.
                 */
                MemoryContextSwitchTo(oldcontext);

                /*
                 * Run the portal to completion, and then drop it (and the receiver).
                 */
                (void) PortalRun(portal,
                                                 FETCH_ALL,
                                                 true,  /* always top level */
                                                 receiver,
                                                 receiver,
                                                 &qc);

                receiver->rDestroy(receiver);

                PortalDrop(portal, false);

                if (lnext(parsetree_list, parsetree_item) == NULL)
                {
                        /*
                         * If this is the last parsetree of the query string, close down
                         * transaction statement before reporting command-complete.  This
                         * is so that any end-of-transaction errors are reported before
                         * the command-complete message is issued, to avoid confusing
                         * clients who will expect either a command-complete message or an
                         * error, not one and then the other.  Also, if we're using an
                         * implicit transaction block, we must close that out first.
                         */
                        if (use_implicit_block)
                                EndImplicitTransactionBlock();
                        finish_xact_command();
                }
                else if (IsA(parsetree->stmt, TransactionStmt))
                {
                        /*
                         * If this was a transaction control statement, commit it. We will
                         * start a new xact command for the next command.
                         */
                        finish_xact_command();
                }
                else
                {
                        /*
                         * We had better not see XACT_FLAGS_NEEDIMMEDIATECOMMIT set if
                         * we're not calling finish_xact_command().  (The implicit
                         * transaction block should have prevented it from getting set.)
                         */
                        Assert(!(MyXactFlags & XACT_FLAGS_NEEDIMMEDIATECOMMIT));

                        /*
                         * We need a CommandCounterIncrement after every query, except
                         * those that start or end a transaction block.
                         */
                        CommandCounterIncrement();

                        /*
                         * Disable statement timeout between queries of a multi-query
                         * string, so that the timeout applies separately to each query.
                         * (Our next loop iteration will start a fresh timeout.)
                         */
                        disable_statement_timeout();
                }

                /*
                 * Tell client that we're done with this query.  Note we emit exactly
                 * one EndCommand report for each raw parsetree, thus one for each SQL
                 * command the client sent, regardless of rewriting. (But a command
                 * aborted by error will not send an EndCommand report at all.)
                 */
                EndCommand(&qc, dest, false);

                /* Now we may drop the per-parsetree context, if one was created. */
                if (per_parsetree_context)
                        MemoryContextDelete(per_parsetree_context);
        }                                                       /* end loop over parsetrees */

        /*
         * Close down transaction statement, if one is open.  (This will only do
         * something if the parsetree list was empty; otherwise the last loop
         * iteration already did it.)
         */
        finish_xact_command();

        /*

