        tsm = GetTsmRoutine(tsc->tsmhandler);
        tsm->SampleScanGetSampleSize(root, rel, tsc->args,
                                                                 &pages, &tuples);

        /*
         * For the moment, because we will only consider a SampleScan path for the
         * rel, it's okay to just overwrite the pages and tuples estimates for the

create_plan(PlannerInfo *root, Path *best_path)
{
        Plan       *plan;

        /* plan_params should not be in use in current query level */
        Assert(root->plan_params == NIL);

        /* Initialize this module's workspace in PlannerInfo */
        root->curOuterRels = NULL;
        root->curOuterParams = NIL;

        /* Recursively process the path tree, demanding the correct tlist result */
        plan = create_plan_recurse(root, best_path, CP_EXACT_TLIST);

        /*
         * Make sure the topmost plan node's targetlist exposes the original
         * column names and other decorative info.  Targetlists generated within
         * the planner don't bother with that stuff, but we must have it on the
         * top-level tlist seen at execution time.  However, ModifyTable plan
         * nodes don't have a tlist matching the querytree targetlist.
         */
        if (!IsA(plan, ModifyTable))
                apply_tlist_labeling(plan->targetlist, root->processed_tlist);

        /*
         * Attach any initPlans created in this query level to the topmost plan
         * node.  (In principle the initplans could go in any plan node at or
         * above where they're referenced, but there seems no reason to put them
         * any lower than the topmost node for the query level.  Also, see
         * comments for SS_finalize_plan before you try to change this.)
         */
        SS_attach_initplans(root, plan);

        /* Check we successfully assigned all NestLoopParams to plan nodes */
        if (root->curOuterParams != NIL)
                elog(ERROR, "failed to assign all NestLoopParams to plan nodes");

        /*
         * Reset plan_params to ensure param IDs used for nestloop params are not
         * re-used later
         */
        root->plan_params = NIL;

        return plan;
}

/*
 * create_plan_recurse
 *        Recursive guts of create_plan().
 */
static Plan *
create_plan_recurse(PlannerInfo *root, Path *best_path, int flags)
{
        Plan       *plan;

        /* Guard against stack overflow due to overly complex plans */
        check_stack_depth();

        switch (best_path->pathtype)
        {
                case T_SeqScan:
                case T_SampleScan:
                case T_IndexScan:
                case T_IndexOnlyScan:
                case T_BitmapHeapScan:
                case T_TidScan:
                case T_TidRangeScan:
                case T_SubqueryScan:
                case T_FunctionScan:
                case T_TableFuncScan:
                case T_ValuesScan:
                case T_CteScan:
                case T_WorkTableScan:
                case T_NamedTuplestoreScan:
                case T_ForeignScan:
                case T_CustomScan:
                        plan = create_scan_plan(root, best_path, flags);
                        break;
                case T_HashJoin:
                case T_MergeJoin:
                case T_NestLoop:
                        plan = create_join_plan(root,
                                                                        (JoinPath *) best_path);
                        break;
                case T_Append:
                        plan = create_append_plan(root,
                                                                          (AppendPath *) best_path,
                                                                          flags);
                        break;
                case T_MergeAppend:
                        plan = create_merge_append_plan(root,
                                                                                        (MergeAppendPath *) best_path,
                                                                                        flags);
                        break;
                case T_Result:
                        if (IsA(best_path, ProjectionPath))
                        {
                                plan = create_projection_plan(root,
                                                                                          (ProjectionPath *) best_path,
                                                                                          flags);
                        }
                        else if (IsA(best_path, MinMaxAggPath))
                        {
                                plan = (Plan *) create_minmaxagg_plan(root,
                                                                                                          (MinMaxAggPath *) best_path);
                        }
                        else if (IsA(best_path, GroupResultPath))
                        {
                                plan = (Plan *) create_group_result_plan(root,
                                                                                                                 (GroupResultPath *) best_path);
                        }
                        else
                        {
                                /* Simple RTE_RESULT base relation */
                                Assert(IsA(best_path, Path));
                                plan = create_scan_plan(root, best_path, flags);
                        }
                        break;
                case T_ProjectSet:
                        plan = (Plan *) create_project_set_plan(root,
                                                                                                        (ProjectSetPath *) best_path);
                        break;
                case T_Material:
                        plan = (Plan *) create_material_plan(root,
                                                                                                 (MaterialPath *) best_path,
                                                                                                 flags);
                        break;
                case T_Memoize:
                        plan = (Plan *) create_memoize_plan(root,
                                                                                                (MemoizePath *) best_path,
                                                                                                flags);
                        break;
                case T_Unique:
                        if (IsA(best_path, UpperUniquePath))
                        {
                                plan = (Plan *) create_upper_unique_plan(root,
                                                                                                                 (UpperUniquePath *) best_path,
                                                                                                                 flags);
                        }
                        else
                        {
                                Assert(IsA(best_path, UniquePath));
                                plan = create_unique_plan(root,
                                                                                  (UniquePath *) best_path,
                                                                                  flags);
                        }
                        break;
                case T_Gather:
                        plan = (Plan *) create_gather_plan(root,
                                                                                           (GatherPath *) best_path);
                        break;
                case T_Sort:
                        plan = (Plan *) create_sort_plan(root,
                                                                                         (SortPath *) best_path,
                                                                                         flags);
                        break;
                case T_IncrementalSort:
                        plan = (Plan *) create_incrementalsort_plan(root,
                                                                                                                (IncrementalSortPath *) best_path,
                                                                                                                flags);
                        break;
                case T_Group:
                        plan = (Plan *) create_group_plan(root,
                                                                                          (GroupPath *) best_path);

(GroupPath *) best_path);
                        break;
                case T_Agg:
                        if (IsA(best_path, GroupingSetsPath))
                                plan = create_groupingsets_plan(root,
                                                                                                (GroupingSetsPath *) best_path);
                        else
                        {
                                Assert(IsA(best_path, AggPath));
                                plan = (Plan *) create_agg_plan(root,
                                                                                                (AggPath *) best_path);
                        }
                        break;
                case T_WindowAgg:
                        plan = (Plan *) create_windowagg_plan(root,
                                                                                                  (WindowAggPath *) best_path);
                        break;
                case T_SetOp:
                        plan = (Plan *) create_setop_plan(root,
                                                                                          (SetOpPath *) best_path,
                                                                                          flags);
                        break;
                case T_RecursiveUnion:
                        plan = (Plan *) create_recursiveunion_plan(root,
                                                                                                           (RecursiveUnionPath *) best_path);
                        break;
                case T_LockRows:
                        plan = (Plan *) create_lockrows_plan(root,
                                                                                                 (LockRowsPath *) best_path,
                                                                                                 flags);
                        break;
                case T_ModifyTable:
                        plan = (Plan *) create_modifytable_plan(root,
                                                                                                        (ModifyTablePath *) best_path);
                        break;
                case T_Limit:
                        plan = (Plan *) create_limit_plan(root,
                                                                                          (LimitPath *) best_path,
                                                                                          flags);
                        break;
                case T_GatherMerge:
                        plan = (Plan *) create_gather_merge_plan(root,
                                                                                                         (GatherMergePath *) best_path);
                        break;
                default:
                        elog(ERROR, "unrecognized node type: %d",
                                 (int) best_path->pathtype);
                        plan = NULL;            /* keep compiler quiet */
                        break;
        }

        return plan;
}

